// SPDX-License-Identifier: MIT
pragma solidity ^0.8.4;

import "@openzeppelin/contracts/token/ERC721/ERC721.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/security/Pausable.sol";
import "@openzeppelin/contracts/security/ReentrancyGuard.sol";
import "@openzeppelin/contracts/utils/Address.sol";
import "@openzeppelin/contracts/utils/math/SafeMath.sol";

contract LINKEDCollectorsPass is ERC721, Ownable, Pausable, ReentrancyGuard {
    using Address for address payable;
    using SafeMath for uint256;

    uint256 public constant MAX_SUPPLY = 1000;
    uint256 public immutable tokenPrice = 0.05 ether;
    address public developerAddress;
    address public safeAddress;

    event Minted(address indexed to, uint256 tokenId);
    event Paused(address account);
    event Unpaused(address account);
    event AdminAdded(address indexed admin);
    event TokenPriceUpdated(uint256 newPrice);
    event Withdrawal(address indexed receiver, uint256 amount);

    modifier onlyAdmin() {
        require(msg.sender == owner() || msg.sender == safeAddress, "Not an admin");
        _;
    }

    constructor() ERC721("LINKED Collectors Pass", "LCP") {
        developerAddress = msg.sender;
        safeAddress = address(0xYourSafeAddressHere); // Replace with actual safe address
    }

    function mint() external payable whenNotPaused {
        uint256 currentSupply = totalSupply();
        require(currentSupply < MAX_SUPPLY, "Max supply reached");
        require(msg.value >= tokenPrice, "Insufficient funds");

        uint256 tokenId = currentSupply;
        _safeMint(msg.sender, tokenId);
        emit Minted(msg.sender, tokenId);
    }

    function burn(uint256 tokenId) external {
        require(_isApprovedOrOwner(msg.sender, tokenId), "Not owner or approved");
        _burn(tokenId);
    }

    function setTokenPrice(uint256 newPrice) external onlyAdmin {
        require(newPrice > 0, "Price must be greater than 0");
        tokenPrice = newPrice;
        emit TokenPriceUpdated(newPrice);
    }

    function addAdmin(address admin) external onlyOwner {
        require(admin != address(0), "Invalid address");
        require(!isContract(admin), "Cannot add contract as admin");
        emit AdminAdded(admin);
    }

    function pause() external onlyAdmin {
        _pause();
        emit Paused(msg.sender);
    }

    function unpause() external onlyAdmin {
        _unpause();
        emit Unpaused(msg.sender);
    }

    function withdraw() external onlyOwner nonReentrant {
        uint256 balance = address(this).balance;
        bool success = payable(developerAddress).send(balance);
        require(success, "Transfer failed");
        emit Withdrawal(developerAddress, balance);
    }

    function isContract(address addr) internal view returns (bool) {
        uint256 size;
        assembly { size := extcodesize(addr) }
        return size > 0;
    }
}
